const out = [];
for (const item of $input.all()) {
  const b = (item.json && item.json.body) || {};
  const af = b.all_fields || {};
  const data = af.data || {};
  if (!data.deepseek) continue;  // DEDUP : ne poster QUE l'alerte enrichie IA (la brute est un doublon)
  const ds = data.deepseek || {};
  const src = data.alerte_source || {};
  if (!src.rule_id) continue;   // pas de carte si origine inconnue (anti carte branded deepseek)
  const rule = af.rule || {};
  const agent = af.agent || {};
  const level = Number(src.level || rule.level || 0);
  if (level < 8) continue;   // SEUIL #alertes : niveau d'origine (alerte_source.level) >= 8
  const rid = src.rule_id || rule.id || b.rule_id || 'N/A';
  const desc = src.description || rule.description || b.title || 'Alerte';
  const ag = src.agent || agent.name || 'N/A';
  const srcip = data.srcip || '';
  const crit = ds.criticite || '';
  const resume = ds.resume || '';
  const mitre = ds.mitre || '';
  const reco = ds.recommandation || '';
  const ts = String(src.timestamp || '').trim();   // déclenchement = origine (alerte_source) UNIQUEMENT, jamais la ré-injection IA
  const fmtTs = (t)=>{ try{ const d=new Date(t); if(isNaN(d.getTime())) return String(t||'—'); return d.toLocaleString('fr-FR',{timeZone:'Europe/Paris',day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit',second:'2-digit'})+' (Paris)'; }catch(e){ return String(t||'—'); } };
  // couleur par niveau
  const color = level>=12 ? 15158332 : level>=10 ? 15105570 : level>=8 ? 16763904 : 3447003;
  const sev = level>=12 ? 'CRITIQUE' : level>=10 ? 'ELEVE' : level>=8 ? 'MOYEN' : 'INFO';
  const cut = (v,n)=>{ v = (v==null||v==='') ? '—' : String(v); return v.length>(n||1024) ? v.slice(0,(n||1024)-1)+'…' : v; };
  const WZ_BASE='https://100.73.179.63';
  const wzLink=(k,v)=>{ if(v==null||v==='')return ''; v=String(v); const g="(filters:!(('$state':(store:globalState),meta:(alias:!n,disabled:!f,index:'wazuh-alerts-*',key:"+k+",negate:!f,params:(query:'"+v+"'),type:phrase),query:(match_phrase:("+k+":'"+v+"')))),time:(from:'now-1y',to:'now'))"; return WZ_BASE+"/app/threat-hunting#/overview?tab=general&tabView=events&_g="+encodeURIComponent(g).replace(/[!'()*]/g,c=>'%'+c.charCodeAt(0).toString(16).toUpperCase()); };
  const wzUrl=(function(){ const id=src.alert_id||''; if(!id) return ''; let from='now-1y',to='now'; const ep=parseInt(String(id).split('.')[0],10); if(!isNaN(ep)){ from=new Date((ep-21600)*1000).toISOString(); to=new Date((ep+21600)*1000).toISOString(); } const g="(filters:!(('$state':(store:globalState),meta:(alias:!n,disabled:!f,index:'wazuh-alerts-*',key:id,negate:!f,params:(query:'"+id+"'),type:phrase),query:(match_phrase:(id:'"+id+"')))),time:(from:'"+from+"',to:'"+to+"'))"; return WZ_BASE+"/app/threat-hunting#/overview?tab=general&tabView=events&_g="+encodeURIComponent(g).replace(/[!'()*]/g,function(c){return '%'+c.charCodeAt(0).toString(16).toUpperCase();}); })();
  const fi = data.fileintel || null;
  const ii = data.ipintel || null;
  const fields = [
    { name: '🖥️ Agent', value: (wzLink('agent.name',ag)?('['+cut(ag,200)+']('+wzLink('agent.name',ag)+')'):cut(ag,256)), inline: true },
  ];
  if (!fi && srcip) fields.push({ name: '🌐 IP source', value: (wzLink('data.srcip',srcip)?('['+srcip+']('+wzLink('data.srcip',srcip)+')'):('`'+srcip+'`')), inline: true });
  fields.push({ name: '🔢 Règle', value: (wzLink('rule.id',rid) ? ('['+cut(String(rid),200)+']('+wzLink('rule.id',rid)+')') : cut(String(rid),256)), inline: true });
  if (fi || ii) fields.push({ name: '🔢 Niveau', value: (wzLink('rule.level',level)?('['+level+' · '+sev+']('+wzLink('rule.level',level)+')'):(level+' · '+sev)), inline: true });
  fields.push({ name: '🕒 Déclenchement', value: ts ? fmtTs(ts) : '—', inline: true });
  if (fi) fields.push({ name: '📄 Fichier', value: cut(fi.file,512), inline: false });
  if (crit)   fields.push({ name: '🎯 Criticité IA', value: cut(crit,256), inline: true });
  if (resume) fields.push({ name: '📝 Résumé IA', value: cut(resume) });
  if (mitre)  fields.push({ name: '🧬 MITRE ATT&CK', value: cut(mitre) });
  if (reco)   fields.push({ name: '💡 Recommandation', value: cut(reco) });
  if (fi) {
    const vt = fi.vt || {}; const ha = fi.ha || {}; const otx = fi.otx || {}; const u = fi.urls || {};
    fields.push({ name: '🦠 VirusTotal', value: (vt.positives!=null ? (vt.positives+'/'+vt.total+' moteurs') : '—'), inline: true });
    fields.push({ name: '🧪 Hybrid Analysis', value: (ha.score!=null ? (ha.score+'/100'+(ha.verdict?(' ('+ha.verdict+')'):'')) : (ha.verdict || '—')), inline: true });
    fields.push({ name: '🌐 AlienVault OTX', value: (otx.file_score!=null ? (otx.file_score+'/10'+((+otx.file_score)>0?' ⚠️':'')) : '—'), inline: true });
    const links = [];
    if (u.vt) links.push('[🦠 VirusTotal]('+u.vt+')');
    if (u.ha) links.push('[🧪 Hybrid Analysis]('+u.ha+')');
    if (u.otx) links.push('[🌐 AlienVault OTX]('+u.otx+')');
    if (links.length) fields.push({ name: '📊 Rapports', value: links.join('   ·   '), inline: false });
  } else if (ii) {
    const vt = ii.vt || {}; const otx = ii.otx || {}; const u = ii.urls || {};
    fields.push({ name: '🦠 VirusTotal', value: (vt.positives!=null ? (vt.positives+'/'+vt.total+' moteurs'+((+vt.positives)>0?' ⚠️':'')) : '—'), inline: true });
    fields.push({ name: '🌐 AlienVault OTX', value: (otx.pulses!=null ? (otx.pulses+' pulses'+((+otx.pulses)>0?' ⚠️':'')) : '—'), inline: true });
    const links = [];
    if (u.vt) links.push('[🦠 VirusTotal]('+u.vt+')');
    if (u.otx) links.push('[🌐 AlienVault OTX]('+u.otx+')');
    if (u.shodan) links.push('[🛰️ Shodan]('+u.shodan+')');
    if (links.length) fields.push({ name: '📊 Rapports', value: links.join('   ·   '), inline: false });
  }
  const embed = {
    title: `🚨 ${desc}`.slice(0,256),
    url: wzUrl || undefined,
    description: `**Niveau ${level}** · ${sev}`,
    color,
    fields,
    footer: { text: `Wazuh SOC · règle ${rid} · id ${src.alert_id || '—'}` },
    timestamp: ts || undefined,
  };
  out.push({ json: { embedJson: JSON.stringify(embed) } });
}
return out;
